<button x-data="{ dark: document.documentElement.classList.contains('dark') }" x-on:dark-mode-toggled.window="dark = document.documentElement.classList.contains('dark')" @click="dark = !dark; localStorage.setItem('dark', dark); document.documentElement.classList.toggle('dark', dark); window.dispatchEvent(new CustomEvent('dark-mode-toggled'))" class="cursor-pointer p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors focus:outline-none" aria-label="Toggle Dark Mode">
    <svg x-cloak x-show="!dark" class="w-6 h-6 text-yellow-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 3v1m0 16v1m8.66-9.66h-1M4.34 12.34h-1m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707"/></svg>
    <svg x-cloak x-show="dark" class="w-6 h-6 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z"/></svg>
</button>
